+  // Check for obviously infinite loops where the exit condition can never be true.
+  BasicBlock *LatchBB = Lp->getLoopLatch();
+  if (LatchBB) {
+    BranchInst *BI = dyn_cast<BranchInst>(LatchBB->getTerminator());
+    if (BI && BI->isConditional()) {
+      Value *Cond = BI->getCondition();
+      // Try to analyze the condition with ScalarEvolution
+      if (SCEV *CondSCEV = PSE.getSE()->getSCEV(Cond)) {
+        // If the condition is always false, the loop is infinite
+        if (PSE.getSE()->isKnownPredicate(ICmpInst::ICMP_EQ, CondSCEV, 
+                                          PSE.getSE()->getConstant(Cond->getType(), 0))) {
+          reportVectorizationFailure("Loop appears to be infinite",
+              "loop control flow is not understood by vectorizer",
+              "InfiniteLoop", ORE, TheLoop);
+          if (DoExtraAnalysis)
+            Result = false;
+          else
+            return false;
+        }
+      }
+    }
+  }
   return Result;
 }

